package com.chaobo.scm.supplier.interfaces.web;import com.chaobo.scm.common.api.*;import com.chaobo.scm.supplier.application.quote.SupplierQuoteApplicationService;import com.chaobo.scm.supplier.application.shared.CommandResult;import com.chaobo.scm.supplier.infrastructure.security.CommandContextFactory;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.security.core.*;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/supplier/v1/quotes") public class SupplierQuoteMaintenanceController{private final SupplierQuoteApplicationService service;private final CommandContextFactory contexts;public SupplierQuoteMaintenanceController(SupplierQuoteApplicationService service,CommandContextFactory contexts){this.service=service;this.contexts=contexts;}@PostMapping("/{id}/void")public ApiResponse<CommandResult> voidQuote(@PathVariable long id,@Valid @RequestBody VoidRequest body,HttpServletRequest request,Authentication auth){return ApiResponse.success(service.voidQuote(id,body.version(),body.reason(),contexts.create(request,auth)),request.getHeader("X-Request-Id"),request.getHeader("X-Trace-Id"));}public record VoidRequest(@PositiveOrZero int version,@NotBlank String reason){}}
